/* eslint-disable @typescript-eslint/no-explicit-any */
import type { Rect, ClipperConfig } from '../types';
import { BrazeIframeSelector } from '../types';

/**
 * Braze IAM Clipper - runs on parent page, applies clip-path to iframe
 */
export class BrazeIframeClipper {
  private config: ClipperConfig;
  private iframe: HTMLIFrameElement | null = null;
  private lastRect: Rect | null = null;
  private mutationObserver: MutationObserver | null = null;
  private isInitialized = false;

  constructor(config: ClipperConfig) {
    this.config = config;
  }

  public init(): void {
    if (this.isInitialized) return;

    this.isInitialized = true;

    window.addEventListener('message', this.handleMessage, true);
    window.addEventListener('resize', this.handleResize);

    this.setupMutationObserver();
    this.findIframe();

    if (this.config.debug) {
      console.log('Survicate: Braze iframe clipper initialized');
    }
  }

  private setupMutationObserver(): void {
    this.mutationObserver = new MutationObserver(() => this.findIframe());
    this.mutationObserver.observe(document.body, {
      childList: true,
      subtree: true,
    });
  }

  private findIframe(): void {
    const iframe = document.querySelector(
      BrazeIframeSelector.IN_APP_MESSAGE
    ) as HTMLIFrameElement | null;

    if (iframe && iframe !== this.iframe) {
      this.iframe = iframe;

      if (this.config.debug) {
        console.log('Survicate: Found Braze IAM iframe');
      }
    }
  }

  private handleMessage = (event: MessageEvent): void => {
    if (!this.iframe || event.source !== this.iframe.contentWindow) return;

    const rect = this.parseRect(event.data);

    if (!rect) return;

    this.applyClipping(this.iframe, rect);
  };

  private parseRect(data: unknown): Rect | null {
    if (data && typeof data === 'object') {
      const obj = data as Record<string, unknown>;

      return obj.type === 'sv__rect' && obj.payload ? this.validateRect(obj.payload) : null;
    }

    return null;
  }

  private validateRect(rect: unknown): Rect | null {
    if (
      rect &&
      typeof rect === 'object' &&
      typeof (rect as any).top === 'number' &&
      typeof (rect as any).left === 'number' &&
      typeof (rect as any).width === 'number' &&
      typeof (rect as any).height === 'number'
    ) {
      const validatedRect = rect as Rect;
      const validated: Rect = {
        top: Math.max(0, Math.round(validatedRect.top)),
        left: Math.max(0, Math.round(validatedRect.left)),
        width: Math.max(0, Math.round(validatedRect.width)),
        height: Math.max(0, Math.round(validatedRect.height)),
      };

      return validated.width > 0 && validated.height > 0 ? validated : null;
    }

    return null;
  }

  private applyClipping(iframe: HTMLIFrameElement, rect: Rect): void {
    document.body.classList.remove('ab-pause-scrolling');

    const viewport = {
      width: window.innerWidth,
      height: window.innerHeight,
    };

    const top = Math.max(0, rect.top);
    const left = Math.max(0, rect.left);
    const right = Math.max(0, viewport.width - (rect.left + rect.width));
    const bottom = Math.max(0, viewport.height - (rect.top + rect.height));

    const clipPath = `inset(${top}px ${right}px ${bottom}px ${left}px)`;

    if (iframe.style.clipPath !== clipPath) {
      iframe.style.setProperty('clip-path', clipPath, 'important');
      iframe.style.setProperty('-webkit-clip-path', clipPath, 'important');

      if (this.config.debug) {
        console.log('Survicate: Applied clip-path:', clipPath);
      }
    }

    this.lastRect = rect;
  }

  private handleResize = (): void => {
    if (this.lastRect && this.iframe) {
      this.applyClipping(this.iframe, this.lastRect);
    }
  };

  public destroy(): void {
    if (this.mutationObserver) {
      this.mutationObserver.disconnect();
    }

    window.removeEventListener('message', this.handleMessage, true);
    window.removeEventListener('resize', this.handleResize);

    if (this.iframe) {
      this.iframe.style.removeProperty('clip-path');
      this.iframe.style.removeProperty('-webkit-clip-path');
    }

    this.iframe = null;
    this.isInitialized = false;
  }
}
