import { BrazeIframeClipper } from './core/clipper';
import type { BrazeBridgeConfig } from './types';

export type { Rect, BrazeBridgeConfig } from './types';
export { BrazeIframeClipper } from './core/clipper';

let clipperInstance: BrazeIframeClipper | null = null;

export function initBrazeBridge(config: BrazeBridgeConfig = {}): void {
  if (clipperInstance) {
    console.warn('Survicate: Braze bridge already initialized');
    return;
  }

  clipperInstance = new BrazeIframeClipper({ debug: config.debug || false });

  clipperInstance.init();

  if (config.debug) {
    console.log('Survicate: Braze bridge initialized (clipper only)');
  }
}

export function destroyBrazeBridge(): void {
  if (!clipperInstance) return;

  clipperInstance.destroy();
  clipperInstance = null;
}
